#!/usr/bin/env node
/**
 * Fetch SVG assets from Figma Desktop's local server (localhost:3845).
 * Run with the Figma file open in Figma Desktop. No API token needed.
 *
 * Reads figma-desktop-asset-urls.json (iconKey -> url). Populates svg/*.svg.
 * That file is generated by the Cursor agent via Figma MCP get_design_context.
 *
 * Usage:
 *   1. Open the Open Icons Figma file in Figma Desktop.
 *   2. node scripts/fetch-from-figma-desktop.js
 *   3. npm run generate-svg-registry && npm run build
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const URLS_FILE = path.join(__dirname, '../figma-desktop-asset-urls.json');
const SVG_DIR = path.join(__dirname, '../svg');

const baseUrl = process.env.FIGMA_DESKTOP_URL || 'http://localhost:3845';

async function main() {
  if (!fs.existsSync(URLS_FILE)) {
    console.error('Missing', URLS_FILE);
    console.error('The Cursor agent must run first to collect asset URLs via Figma MCP (get_design_context).');
    process.exit(1);
  }
  const urls = JSON.parse(fs.readFileSync(URLS_FILE, 'utf8'));
  const entries = Object.entries(urls);
  if (entries.length === 0) {
    console.log('No URLs in', URLS_FILE);
    process.exit(0);
  }
  if (!fs.existsSync(SVG_DIR)) fs.mkdirSync(SVG_DIR, { recursive: true });

  let done = 0;
  let failed = 0;
  for (const [iconKey, url] of entries) {
    const fullUrl = url.startsWith('http') ? url : `${baseUrl}/assets/${url}`;
    try {
      const res = await fetch(fullUrl);
      if (!res.ok) throw new Error(res.status.toString());
      const svg = await res.text();
      const safeKey = iconKey.replace(/[^a-z0-9-]/gi, '-').toLowerCase();
      fs.writeFileSync(path.join(SVG_DIR, `${safeKey}.svg`), svg);
      done++;
    } catch (e) {
      console.warn(iconKey, e.message);
      failed++;
    }
  }
  console.log('Fetched', done, 'SVGs. Failed:', failed);
  console.log('Run: npm run generate-svg-registry && npm run build');
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
